INSERT INTO jobs (job_name, industry, city, company_type, salary_min, salary_max, skills, soft_skills, is_fresh_friendly, friendly_level, jd_content, core_duties, education, major, experience, post_type, bonus_skills, salary_range, post_time, apply_deadline, jd_link, post_category, party_label) VALUES ('行政专员/助理 - 晋城（实习）', '化工 / 能源 / 环保', '晋城', '民营企业', 80000, 100, '熟练使用OFFICE办公软件，有一定电脑使用基础', '沟通、协调能力强，抗压能力强；积极热情、责任心强、性格开朗、讲求效率、乐于接受挑战', 1, '友好', '1. 负责统计、整理和记录供应商、物流和客户数据；2. 负责与客户及合作物流进行日常的业务沟通处理各项相关事宜；3. 操作业务系统、数据录入、更新、汇总各类日常报表并进行分析上报；4. 负责整理档案资料、协助经理处理日常事务；5. 负责上级根据工作需求临时安排的其它工作', '行政事务支持、数据统计与分析、跨部门沟通协调、档案管理', '不限', '无强制专业限制', '可实习3个月，每周到岗6天，接受大一、大二，零基础可实习', '远程实习', '有能源、化工行业相关实习经验；有数据处理相关经验', '80-100元/天', '46107', '46122', 'https://www.shixiseng.com/intern/inn_xemjvrvanudc?pcm=pc_SearchList', '行政类', '甲方（企业自有 HR 岗）'), ('行政专员/助理 - 北京（实习）', '互联网 / IT', '北京', '外资企业', 120, 180, '熟练掌握Word、Excel、PPT等常用办公软件，具备基础数据整理能力', '具有良好的沟通能力和团队合作能力，能快速融入初创团队氛围；学习能力强，细心且有责任心，能高效完成多任务处理', 1, '友好', '1. 协助处理公司行政事务，包括日常办公环境维护、物资采购与管理等；2. 整理各类资料、文件，搭建并维护文档库，确保信息查阅便捷；3. 协助进行财务报销工作，整理报销凭证、跟进报销流程；4. 协助进行合同整理归纳工作；5. 处理上级交办的其他日常工作，如会议筹备、访客接待等', '行政事务支持、财务辅助、档案管理、会议活动组织、接待外联', '本科及以上', '专业不限，有财会背景可加分，对AI行业有热情者优先', '本科或研究生在校生，每周至少保证到岗实习4天，连续实习3个月及以上', '日常实习', '有财会背景；有AI行业相关实习经验；有行政相关实习经验', '120-180元/天', '46098', '46129', 'https://www.shixiseng.com/intern/inn_syw6trq1ldqd?pcm=pc_SearchList', '行政类', '甲方（企业自有 HR 岗）'), ('行政专员实习生 - 北京（实习）', '制造', '北京', '民营企业', 150, 250, '1. 熟练使用Office办公软件；2. 具备基础的数据分析能力', '亲和力强、善于沟通、乐观积极、服务意识强；具备较好的学习能力', 1, '友好', '1. 负责所服务办公区/业务部门行政需求的响应、并高效反馈；2. 负责日常行政事务的执行落地，并提出优化建议；3. 协助企业文化的宣导与传递；4. 负责差旅数据分析', '行政事务支持、企业文化宣导、数据分析、跨部门协调', '本科及以上', '行政管理、企业管理、工商管理专业优先', '可实习3个月，每周到岗5天，有知名大型企业实习经验优先考虑', '日常实习', '有知名大型企业实习经验；行政管理相关专业；有行政相关实习经验', '150-250元/天', '46098', NULL, 'https://www.shixiseng.com/intern/inn_mkmr2u6r3d4c?pcm=pc_SearchList', '行政类', '甲方（企业自有 HR 岗）'), ('行政人事专员 - 上海（实习）', '医疗健康 / 生物', '上海', '国企 / 央企', 120, 180, '1. 熟练使用Office办公软件；2. 具备公文撰写、PPT制作能力', '工作认真负责，执行力强，具备良好的沟通协调能力、文字撰写能力，有保密意识', 1, '友好', '1. 负责企业号的运营和维护，包括但不限于公司各条线活动的跟进、拍照、记录，通讯稿的整理、排版、发送及整理归档；2. 负责公司会务体系的建设，包括但不限于会议通知的发送、会议纪要的记录以及会务的组织和策划等；3. 负责对外的联系和沟通工作，做好各类事项的跟进、传达和完成，包括但不限于行业协会、上级单位、开发区等各级政府和组织；4. 负责公司协会会费的管控和跟进；5. 负责对外企业介绍、公司活动宣传等各类活动的接洽、组织、策划、宣传、推广等；6. 负责公司会议室及办公环境的整洁和美化；7. 负责公司办公文件的拟稿、整理、归档；8. 负责公司办公用品的管理、规划以及跟进服务；9. 负责公司各项总结、PPT等汇报的拟稿，负责领导各类演讲稿的撰写以及各项活动的对接及跟进；10. 负责公司电子屏、电视机、文化墙等宣传材料的日常投影、播放维护；11. 完成领导安排的其他事项', '行政事务支持、企业文化宣传、会议活动组织、公文撰写、接待外联', '本科及以上', '无强制专业限制', '可实习3个月，每周到岗5天，接受大一、大二，零基础可实习', '日常实习', '有医药行业、国企行政相关实习经验；有新媒体运营、公文撰写相关经验', '120-180元/天', '45054', '46112', 'https://www.shixiseng.com/intern/inn_pt7qziu5zhm17?pcm=pc_SearchList', '行政类', '甲方（企业自有 HR 岗）'), ('行政专员/助理 - 长沙（实习）', '教育 / 培训', '长沙', '民营企业', 150, 300, '熟练使用办公软件及各类办公设备', '品行端正，具备良好的职业操守与保密意识；工作细致严谨、责任心强，具备良好的沟通协调能力', 1, '友好', '1. 负责公司日常行政事务处理，包括文件收发流转、档案归档管理、公文撰写、印章管理等基础办公工作，保障行政体系规范运转；2. 统筹办公环境维护、办公用品采购与库存管理、固定资产登记盘点，落实办公区后勤保障服务；3. 负责公司会议筹备、人员行程安排等工作，做好会议记录与纪要整理归档；4. 配合各部门完成跨部门沟通协调、数据统计上报，高效完成上级交办的其他行政相关工作', '行政事务支持、固定资产管理、会议活动组织、档案管理、跨部门协调', '不限', '无强制专业限制', '可实习3个月，每周到岗2天，接受大一、大二，零基础可实习', '日常实习', '有教育行业、行政相关实习经验', '150-300元/天', '46096', '46186', 'https://www.shixiseng.com/intern/inn_mo1xprgo31k0?pcm=pc_SearchList', '行政类', '甲方（企业自有 HR 岗）');